      keepEnglish: true,
      ja: {"term":"悲観的排他制御","kana":"ヒカンテキハイタセイギョ","note":"データの更新競合が頻発すると想定し、読込時または更新前に排他ロックを取得して他の割込を防ぐ制御。"},
      zh: {"term":"悲观并发控制","explanation":"假设数据冲突频繁发生，在读取或修改数据前立即加上独占锁，直到事务完成才释放，防止他人同时修改的机制，简称 PCC。"},
      en: {"term":"Pessimistic Concurrency Control","explanation":"A concurrency control method where locks are acquired before data access to prevent conflicts, blocking other transactions until the lock is released."},
      my: {"term":"စိုးရိမ်မှုရှိသော ပူးတွဲထိန်းချုပ်မှုစနစ်","explanation":"ဒေတာအပြိုင်ပြင်ဆင်မှုများကြောင့် အမှားမဖြစ်စေရန် ဖတ်စဉ် သို့မဟုတ် မပြင်မီကတည်းက သော့ခတ် (lock) ထားသည့် စနစ် (PCC)。","needsReview":true},
      vi: {"term":"Kiểm soát truy cập đồng thời bi quan","explanation":"Cơ chế thiết lập khóa ngăn chặn xung đột ngay khi truy cập hàng dữ liệu, chặn giao dịch khác đến khi khóa giải phóng。","needsReview":true},
      fr: {"term":"Contrôle d'accès concurrent pessimiste","explanation":"Méthode de verrouillage anticipé (PCC) bloquant les ressources avant modification pour empêcher tout conflit。","needsReview":true},
      aliases: ["PCC","Pessimistic Locking"],
      related: ["optimistic_concurrency_control"],
      example: {"sql":"SELECT ... FOR UPDATE is a classic implementation of pessimistic locking in SQL."},
      source: "project-glossary-v2"
