      zh: {"term":"专利权","explanation":"工业产权之一。发明人向国家专利机关申请并获得批准后，在法定期限内对其发明创造享有的独占使用权。"},
      en: {"term":"Patent Right","explanation":"An exclusive right granted by a government agency to an inventor for a limited time, preventing others from making, using, or selling the invention."},
      my: {"term":"တီထွင်မှု မူပိုင်ခွင့်","explanation":"တီထွင်သူတစ်ဦးအား ၎င်း၏ တီထွင်ဖန်တီးမှုကို အခြားသူများ ခွင့်ပြုချက်မရှိဘဲ ထုတ်လုပ်ရောင်းချခြင်းမပြုနိုင်ရန် အစိုးရက သတ်မှတ်ပေးသည့် သီးသန့်အခွင့်အရေး。","needsReview":true},
      vi: {"term":"Quyền sáng chế","explanation":"Quyền độc quyền do cơ quan nhà nước cấp cho nhà sáng chế trong một thời gian nhất định để ngăn cản người khác sao chép thương mại。","needsReview":true},
      fr: {"term":"Droit de brevet","explanation":"Titre de propriété industrielle accordant à un inventeur un monopole d'exploitation sur son invention pour une période limitée。","needsReview":true},
      aliases: ["Patent","exclusive utility right"],
      related: ["copyright_protection"],
      example: {"text":"Our technology team filed a patent right application for the new database query optimizer."},
