      vi: {"term":"Mã trạng thái HTTP 2xx","explanation":"Nhóm mã phản hồi HTTP của máy chủ biểu thị yêu cầu của khách hàng đã được tiếp nhận và xử lý thành công。","needsReview":true},
      fr: {"term":"Codes d'état HTTP 2xx / Réussite","explanation":"Classe de codes de statut HTTP confirmant que la requête du client a été traitée et acceptée avec succès (ex. 200 OK)。","needsReview":true},
      aliases: ["HTTP 2xx","HTTP 200 OK"],
      related: [],
      example: {"text":"The server returns HTTP status codes 2xx when resources are successfully retrieved."},
