      vi: {"term":"Mã trạng thái HTTP 5xx","explanation":"Nhóm mã phản hồi báo lỗi từ phía máy chủ (server-side errors) khi không thể xử lý yêu cầu hợp lệ của trình duyệt。","needsReview":true},
      fr: {"term":"Codes d'état HTTP 5xx / Erreur serveur","explanation":"Catégorie de codes HTTP indiquant que le serveur a rencontré une erreur interne en traitant la requête (ex. 500, 503)。","needsReview":true},
      aliases: ["HTTP 5xx","server error status codes"],
      related: ["http_status_codes_4xx"],
      example: {"text":"We checked the backend server logs when users reported seeing HTTP status codes 5xx."},
      source: "project-glossary-v2"
